    ["Лапаротомия, дренирование брюшной полости", "Холедохотомия, дренирование брюшной полости", "холедоходуоденостомия", "эндоскопическая папиллосфинктеротомия", "Холецистэктомия, дренирование брюшной полости"],  # варианты
    5,  # номер правильного варианта (1-n)
