    ["Доступ по Пфаненштилю", "Верхнесрединная лапаротомия", "Нижнесрединная лапаротомия", "Косой переменный доступ слева", "Среднесрединная лапаротомия"],  # варианты
    5,  # номер правильного варианта (1-n)
